<section class="portal-page narrow"><div class="portal-head"><div><span class="eyebrow">ONLINE APPOINTMENT</span><h1>Book an Appointment</h1><p>Select a doctor and date to see available time slots.</p></div><a class="btn outline" href="<?=url('dashboard')?>">Dashboard</a></div><div class="booking-steps"><b class="active">1 Doctor</b><b>2 Date & Time</b><b>3 Confirm</b></div><form class="hospital-form booking-form" method="get" action="<?=url('book-appointment')?>"><div class="form-grid"><label>Select Doctor<select name="doctor" required><option value="">Choose doctor</option><?php foreach($doctors as$d):?><option value="<?=$d['id']?>" <?=$selectedDoctor===(int)$d['id']?'selected':''?>><?=e($d['name'].' — '.$d['specialization'])?></option><?php endforeach;?></select></label><label>Preferred Date<input type="date" name="date" min="<?=date('Y-m-d')?>" value="<?=e($selectedDate)?>" required></label></div><button class="btn outline">Check Available Times</button></form><?php if($selectedDoctor&&$selectedDate):?><form class="hospital-form booking-form final-booking" method="post" action="<?=url('book-appointment')?>"><?=csrf_field()?><input type="hidden" name="doctor_id" value="<?=$selectedDoctor?>"><input type="hidden" name="appointment_date" value="<?=e($selectedDate)?>"><h2>Available times for <?=date('l, d F Y',strtotime($selectedDate))?></h2><div class="slot-grid"><?php foreach($slots as$s):?><label class="slot"><input type="radio" name="appointment_time" value="<?=e($s['start_time'])?>" required><span><?=date('h:i A',strtotime($s['start_time']))?></span></label><?php endforeach;?></div><?php if(!$slots):?><div class="empty">No available schedule for this doctor on the selected date. Choose another date.</div><?php endif;?><small class="field-error"><?=e($errors['appointment_time'][0]??'')?></small><label>Reason for visit<textarea name="reason" rows="4" maxlength="500" required><?=e($old['reason']??'')?></textarea><small><?=e($errors['reason'][0]??'')?></small></label><label class="check"><input type="checkbox" required> I confirm that the information is correct and this is not an emergency request.</label><?php if($slots):?><button class="btn">Review and Confirm Appointment</button><?php endif;?></form><?php endif;?></section>

